<style>
	div {
		/* hsl() hue as an angle with explicit units (rad/turn/grad), space + comma syntax */
		color: hsl(2rad 50% 50%);
		background: hsl(0.5turn, 50%, 50%);
		border-color: hsl(100grad 50% 50% / 0.5);
		/* deg is the common contrast case */
		outline-color: hsl(120deg 50% 50%);
	}
</style>
